<h3 class="fw-bold mb-4">Settings</h3>
<form>
    <div class="row g-4">
        <div class="col-md-6"><label for="fullName" class="form-label">Full Name</label><input type="text" class="form-control" id="fullName" placeholder="Your First Name"></div>
        <div class="col-md-6"><label for="nickName" class="form-label">Nick Name</label><input type="text" class="form-control" id="nickName" placeholder="Your Nick Name"></div>
        <div class="col-md-6"><label for="gender" class="form-label">Gender</label><select id="gender" class="form-select"><option selected>Choose...</option><option>Male</option><option>Female</option></select></div>
        <div class="col-md-6"><label for="country" class="form-label">Country</label><input type="text" class="form-control" id="country" placeholder="Your Country"></div>
        <div class="col-md-6"><label for="language" class="form-label">Language</label><input type="text" class="form-control" id="language" placeholder="e.g., English"></div>
        <div class="col-md-6"><label for="timeZone" class="form-label">Time Zone</label><input type="text" class="form-control" id="timeZone" placeholder="e.g., (GMT+8) Singapore"></div>
    </div>
    <div class="d-flex justify-content-end mt-5"><button type="button" class="btn btn-light me-3">Cancel</button><button type="submit" class="btn btn-primary-light px-4">Save</button></div>
</form>
